'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { z } from 'zod'
import { DashboardHeader } from '@/components/dashboard/header'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { ArrowLeft, Loader2, CalendarIcon } from 'lucide-react'
import Link from 'next/link'

const deliveryTourSchema = z.object({
    tourDate: z.string().min(1, 'La date est requise'),
    driverName: z.string().min(1, 'Le nom du chauffeur est requis'),
    vehicleId: z.string().optional(), // In a real app we would load options from /api/vehicles
    depotId: z.string().optional(),   // In a real app we would load options from /api/depots
    notes: z.string().optional(),
})

type DeliveryTourForm = z.infer<typeof deliveryTourSchema>

export default function NewDeliveryPage() {
    const router = useRouter()
    const [isLoading, setIsLoading] = useState(false)
    const [error, setError] = useState<string | null>(null)

    const {
        register,
        handleSubmit,
        formState: { errors },
    } = useForm<DeliveryTourForm>({
        resolver: zodResolver(deliveryTourSchema),
        defaultValues: {
            tourDate: new Date().toISOString().split('T')[0],
        }
    })

    async function onSubmit(data: DeliveryTourForm) {
        setIsLoading(true)
        setError(null)

        try {
            const response = await fetch('/api/deliveries', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(data),
            })

            const result = await response.json()

            if (!response.ok) {
                setError(result.error || 'Une erreur est survenue')
                return
            }

            router.push('/dashboard/deliveries')
            router.refresh()
        } catch {
            setError("Une erreur est survenue. L'API de livraison (/api/deliveries) n'est peut-être pas encore implémentée.")
        } finally {
            setIsLoading(false)
        }
    }

    return (
        <div className="flex flex-col min-h-screen">
            <DashboardHeader
                title="Ajouter une livraison"
                description="Planifier une nouvelle tournée de livraison"
            />
            <main className="flex-1 p-6 lg:p-10 animate-in fade-in slide-in-from-bottom-4 duration-700">
                <div className="mb-6">
                    <Button variant="ghost" size="sm" asChild>
                        <Link href="/dashboard/deliveries">
                            <ArrowLeft className="h-4 w-4 mr-2" />
                            Retour
                        </Link>
                    </Button>
                </div>

                <form onSubmit={handleSubmit(onSubmit)} className="max-w-2xl space-y-6">
                    {error && (
                        <div className="rounded-lg bg-destructive/10 border border-destructive/20 p-4 text-sm text-destructive">
                            {error}
                        </div>
                    )}

                    <Card className="rounded-[2.5rem] border-slate-200/60 shadow-sm overflow-hidden">
                        <CardHeader className="px-8 py-8 border-b border-slate-100">
                            <CardTitle className="text-xl font-black text-slate-950">Nouvelle tournée de livraison</CardTitle>
                            <CardDescription>Configurez la tournée en renseignant les détails de la livraison</CardDescription>
                        </CardHeader>
                        <CardContent className="p-8 space-y-6">
                            <div className="grid gap-4 sm:grid-cols-2">
                                <div className="space-y-2">
                                    <Label htmlFor="tourDate">Date de la tournée *</Label>
                                    <div className="relative">
                                        <Input
                                            id="tourDate"
                                            type="date"
                                            {...register('tourDate')}
                                            disabled={isLoading}
                                        />
                                    </div>
                                    {errors.tourDate && (
                                        <p className="text-sm text-destructive">{errors.tourDate.message}</p>
                                    )}
                                </div>

                                <div className="space-y-2">
                                    <Label htmlFor="driverName">Chauffeur *</Label>
                                    <Input
                                        id="driverName"
                                        placeholder="Nom du chauffeur"
                                        {...register('driverName')}
                                        disabled={isLoading}
                                    />
                                    {errors.driverName && (
                                        <p className="text-sm text-destructive">{errors.driverName.message}</p>
                                    )}
                                </div>
                            </div>

                            <div className="grid gap-4 sm:grid-cols-2">
                                <div className="space-y-2">
                                    <Label htmlFor="vehicleId">Véhicule (UUID optionnel)</Label>
                                    <Input
                                        id="vehicleId"
                                        placeholder="Sélection du véhicule..."
                                        {...register('vehicleId')}
                                        disabled={isLoading}
                                    />
                                    <p className="text-xs text-muted-foreground">Normalement, ceci serait une liste déroulante.</p>
                                </div>

                                <div className="space-y-2">
                                    <Label htmlFor="depotId">Dépôt (UUID optionnel)</Label>
                                    <Input
                                        id="depotId"
                                        placeholder="Sélection du dépôt source..."
                                        {...register('depotId')}
                                        disabled={isLoading}
                                    />
                                    <p className="text-xs text-muted-foreground">Normalement, ceci serait une liste déroulante.</p>
                                </div>
                            </div>

                            <div className="space-y-2">
                                <Label htmlFor="notes">Notes pour la livraison</Label>
                                <Textarea
                                    id="notes"
                                    placeholder="Instructions particulières ou informations supplémentaires..."
                                    {...register('notes')}
                                    disabled={isLoading}
                                />
                            </div>

                            <div className="rounded-lg bg-blue-50 border border-blue-200 p-4 text-sm text-blue-800 animate-in fade-in slide-in-from-top-2">
                                <div className="font-bold mb-1">Information pour le développement</div>
                                L'API '/api/deliveries' n'est pas encore créée par défaut. L'envoi du formulaire provoquera probablement une erreur technique que nous pourrons corriger en écrivant cette route.
                            </div>
                        </CardContent>
                    </Card>

                    <div className="flex justify-end gap-4">
                        <Button type="button" variant="outline" asChild disabled={isLoading}>
                            <Link href="/dashboard/deliveries">Annuler</Link>
                        </Button>
                        <Button type="submit" disabled={isLoading}>
                            {isLoading ? (
                                <>
                                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                                    Création...
                                </>
                            ) : (
                                'Planifier la tournée'
                            )}
                        </Button>
                    </div>
                </form>
            </main>
        </div>
    )
}
